    # Make a copy to avoid modifying the original graph
    graph_copy = graph_data.copy()

    target_name = 'ju1.a1.m3'
    target_type = 'EK_AGG_BLOCK'
    target_node = None

    # Find the target AGG_BLOCK node by name and type
    for node_id, node_data in graph_copy.nodes(data=True):
        if isinstance(node_data.get('type'), list) and target_type in node_data['type'] and node_data.get('name') == target_name:
