def process_graph(graph_data):
    # copy the graph to avoid modifying the input
    G = graph_data.copy()

    # locate the parent chassis node by its name attribute
    parent_node = None
    for node, data in G.nodes(data=True):
        if data.get('name') == 'ju1.a1.m4':
            parent_node = node
            break

    # if parent not found, count stays zero
    if parent_node is None:
        packet_switch_count = 0
    else:
        # add the new packet switch node
        new_node = 'new_EK_PACKET_SWITCH_38'
        G.add_node(new_node, name=new_node, type=['EK_PACKET_SWITCH'])
        # connect it under the parent with a CONTAINS relationship
        G.add_edge(parent_node, new_node, type='RK_CONTAINS')

        # breadth‑first search from the parent to count all packet switches
        queue = [parent_node]
        visited = set()
        packet_switch_count = 0
        while queue:
            current = queue.pop(0)
            if current in visited:
                continue
            visited.add(current)
            node_data = G.nodes[current]
            if 'EK_PACKET_SWITCH' in node_data.get('type', []):
                packet_switch_count += 1
            # follow only RK_CONTAINS edges outward
            for successor in G.successors(current):
                edge_data = G.get_edge_data(current, successor)
                if edge_data and edge_data.get('type') == 'RK_CONTAINS':
                    if successor not in visited:
                        queue.append(successor)

    # prepare the output
    return_object = {
        'type': 'text',
        'data': str(packet_switch_count),
        'updated_graph': nx.readwrite.json_graph.node_link_data(G)
    }
    return return_object
